Create a ScrollView, calculate grid positions, and add ImageView items:

```typescript
const COLS = 4;
const CELL_SIZE = 70;
const PADDING = 10;
const items: string[] = [/* array of icon filenames */];
const rows = Math.ceil(items.length / COLS);
const innerHeight = Math.max(rows * (CELL_SIZE + PADDING) + PADDING, 400);

const sv = new ccui.ScrollView();
sv.setSize(cc.size(4 * (CELL_SIZE + PADDING) + PADDING, 400));
sv.setInnerContainerSize(cc.size(sv.getSize().width, innerHeight));
sv.setDirection(ccui.ScrollView.DIR_VERTICAL);
sv.setBounceEnabled(true);
sv.setPosition(40, 40);

items.forEach((icon, i) => {
    const col = i % COLS;
    const row = Math.floor(i / COLS);
    const x = PADDING + col * (CELL_SIZE + PADDING) + CELL_SIZE / 2;
    const y = innerHeight - (PADDING + row * (CELL_SIZE + PADDING) + CELL_SIZE / 2);

    const img = new ccui.ImageView(icon);
    img.setScale9Enabled(true);
    img.setSize(cc.size(CELL_SIZE, CELL_SIZE));
    img.setPosition(x, y);
    img.setTouchEnabled(true);
    img.addClickEventListener(() => this.onItemSelected(i));
    sv.getInnerContainer().addChild(img);
});

this.addChild(sv);
sv.jumpToTop();
```

