Schedule a periodic update that increments the bar's percent:

```typescript
const bar = new ccui.LoadingBar('loading_bar.png', 0);
bar.setDirection(ccui.LoadingBar.TYPE_LEFT);
bar.setPosition(240, 100);
this.addChild(bar);

const label = new ccui.Text('Loading... 0%', 'Arial', 18);
label.setPosition(240, 140);
this.addChild(label);

let progress = 0;
this.schedule((dt: number) => {
    progress += dt * 20; // fill over ~5 seconds
    if (progress >= 100) {
        progress = 100;
        this.unschedule(arguments.callee);
        this.onLoadComplete();
    }
    bar.setPercent(progress);
    label.setString('Loading... ' + Math.floor(progress) + '%');
}, 0.05);
```

Build a modal popup Layout with text and two buttons:

```typescript
function createDialog(title: string, message: string, onOk: () => void, onCancel: () => void): ccui.Layout {
    const winSize = cc.director.getWinSize();

    const overlay = new ccui.Layout();
    overlay.setSize(winSize);
    overlay.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    overlay.setBackGroundColor(cc.color(0, 0, 0));
    overlay.setBackGroundColorOpacity(128);
    overlay.setTouchEnabled(true); // block touches behind

    const dialog = new ccui.Layout();
    dialog.setSize(cc.size(320, 200));
    dialog.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    dialog.setBackGroundColor(cc.color(50, 50, 70));
    dialog.setBackGroundColorOpacity(255);
    dialog.setPosition((winSize.width - 320) / 2, (winSize.height - 200) / 2);
    overlay.addChild(dialog);

    const titleLabel = new ccui.Text(title, 'Arial', 24);
    titleLabel.setPosition(160, 170);
    dialog.addChild(titleLabel);

    const msgLabel = new ccui.Text(message, 'Arial', 16);
    msgLabel.setTextAreaSize(cc.size(280, 80));
    msgLabel.setPosition(160, 110);
    dialog.addChild(msgLabel);

    const okBtn = new ccui.Button('btn_green.png');
    okBtn.setTitleText('OK');
    okBtn.setTitleFontSize(18);
    okBtn.setPosition(100, 30);
    okBtn.addClickEventListener(() => { overlay.removeFromParent(); onOk(); });
    dialog.addChild(okBtn);

    const cancelBtn = new ccui.Button('btn_red.png');
    cancelBtn.setTitleText('Cancel');
    cancelBtn.setTitleFontSize(18);
    cancelBtn.setPosition(220, 30);
    cancelBtn.addClickEventListener(() => { overlay.removeFromParent(); onCancel(); });
    dialog.addChild(cancelBtn);

    return overlay;
}
```

Use five checkboxes and update all when one is tapped:

```typescript
const STAR_COUNT = 5;
const stars: ccui.CheckBox[] = [];
let currentRating = 0;

function setRating(rating: number): void {
    currentRating = rating;
    for (let i = 0; i < STAR_COUNT; i++) {
        stars[i].setSelected(i < rating);
    }
}

for (let i = 0; i < STAR_COUNT; i++) {
    const star = new ccui.CheckBox(
        'star_off.png', 'star_off.png',
        'star_on.png', 'star_off.png', 'star_on.png'
    );
