}

setRating(3); // default 3 stars
```

Listen for the scroll-to-bottom event and dynamically extend the inner container:

```typescript
const ITEM_HEIGHT = 60;
let itemCount = 0;

const sv = new ccui.ScrollView();
sv.setSize(cc.size(300, 400));
sv.setDirection(ccui.ScrollView.DIR_VERTICAL);
sv.setBounceEnabled(true);
sv.setInnerContainerSize(cc.size(300, 400));
sv.setPosition(50, 50);
this.addChild(sv);

function addItems(count: number): void {
    const startIdx = itemCount;
    itemCount += count;
    const newHeight = Math.max(itemCount * ITEM_HEIGHT, 400);
    sv.setInnerContainerSize(cc.size(300, newHeight));

    for (let i = startIdx; i < itemCount; i++) {
        const item = new ccui.Text('Item ' + i, 'Arial', 18);
        item.setPosition(150, newHeight - (i + 0.5) * ITEM_HEIGHT);
        sv.getInnerContainer().addChild(item);
    }
}

addItems(10); // initial load

sv.addEventListener((sender, type) => {
    if (type === ccui.ScrollView.EVENT_SCROLL_TO_BOTTOM) {
        addItems(10);
    }
}, this);
```

