Track touch events on list items and swap positions on drop:

```typescript
const lv = new ccui.ListView();
lv.setSize(cc.size(300, 400));
lv.setDirection(ccui.ScrollView.DIR_VERTICAL);
lv.setItemsMargin(5);
lv.setPosition(50, 50);

function createItem(text: string): ccui.Layout {
    const item = new ccui.Layout();
    item.setSize(cc.size(280, 50));
    item.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    item.setBackGroundColor(cc.color(60, 60, 80));
    item.setTouchEnabled(true);

    const label = new ccui.Text(text, 'Arial', 18);
    label.setPosition(140, 25);
    item.addChild(label);

    let dragStartY = 0;
    item.addTouchEventListener((sender, type) => {
        if (type === ccui.Widget.TOUCH_BEGAN) {
            dragStartY = sender.getWorldPosition().y;
            sender.setBackGroundColor(cc.color(100, 100, 140));
        } else if (type === ccui.Widget.TOUCH_ENDED) {
            sender.setBackGroundColor(cc.color(60, 60, 80));
            const dragEndY = sender.getWorldPosition().y;
            const fromIdx = lv.getIndex(sender);
            const delta = Math.round((dragStartY - dragEndY) / 55);
            const toIdx = Math.max(0, Math.min(lv.getItemsCount() - 1, fromIdx + delta));
            if (fromIdx !== toIdx) {
                lv.removeItem(fromIdx);
                lv.insertCustomItem(sender, toIdx);
            }
        }
    }, this);

    return item;
}

['Item A', 'Item B', 'Item C', 'Item D'].forEach(t => lv.pushBackCustomItem(createItem(t)));
this.addChild(lv);
```

