Combine two Buttons and a Text widget:

```typescript
function createStepper(
    x: number, y: number, min: number, max: number, initial: number,
    onChange: (val: number) => void
): ccui.Layout {
    let value = initial;
    const container = new ccui.Layout();
    container.setSize(cc.size(160, 40));
    container.setPosition(x, y);

    const minusBtn = new ccui.Button('btn_minus.png');
    minusBtn.setPosition(20, 20);
    container.addChild(minusBtn);

    const display = new ccui.Text(String(value), 'Arial', 22);
    display.setPosition(80, 20);
    container.addChild(display);

    const plusBtn = new ccui.Button('btn_plus.png');
    plusBtn.setPosition(140, 20);
    container.addChild(plusBtn);

    minusBtn.addClickEventListener(() => {
        if (value > min) {
            value--;
            display.setString(String(value));
            onChange(value);
        }
    });

    plusBtn.addClickEventListener(() => {
        if (value < max) {
            value++;
            display.setString(String(value));
            onChange(value);
        }
    });

    return container;
}

