Create a Layout banner, position it above the screen, and animate it down:

```typescript
function showNotification(message: string, parent: cc.Node): void {
    const winSize = cc.director.getWinSize();

    const banner = new ccui.Layout();
    banner.setSize(cc.size(winSize.width, 50));
    banner.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    banner.setBackGroundColor(cc.color(30, 150, 30));
    banner.setBackGroundColorOpacity(230);
    banner.setPosition(0, winSize.height); // above screen

    const label = new ccui.Text(message, 'Arial', 18);
    label.setPosition(winSize.width / 2, 25);
    banner.addChild(label);

    parent.addChild(banner, 1000);

    const slideIn = cc.moveTo(0.3, cc.p(0, winSize.height - 50));
    const wait = cc.delayTime(2.0);
    const slideOut = cc.moveTo(0.3, cc.p(0, winSize.height));
    const remove = cc.callFunc(() => banner.removeFromParent());

    banner.runAction(cc.sequence(
        slideIn.easing(cc.easeBackOut()),
        wait,
        slideOut,
        remove
    ));
}
```

Track the active button and reset others on click:

```typescript
function createToggleGroup(
    names: string[], x: number, y: number,
    onSelect: (index: number) => void
): ccui.Layout {
    const group = new ccui.Layout();
    group.setLayoutType(ccui.Layout.LINEAR_HORIZONTAL);
    group.setSize(cc.size(names.length * 110, 50));
    group.setPosition(x, y);

    const buttons: ccui.Button[] = [];
    let activeIdx = 0;

    names.forEach((name, i) => {
        const btn = new ccui.Button('toggle_off.png', 'toggle_on.png');
        btn.setScale9Enabled(true);
        btn.setSize(cc.size(100, 45));
        btn.setTitleText(name);
        btn.setTitleFontSize(16);

        const param = new ccui.LinearLayoutParameter();
        param.setMargin(new ccui.Margin(5, 0, 0, 0));
        btn.setLayoutParameter(param);

        btn.addClickEventListener(() => {
            buttons[activeIdx].loadTextureNormal('toggle_off.png');
            activeIdx = i;
            btn.loadTextureNormal('toggle_on.png');
            onSelect(i);
        });

        buttons.push(btn);
        group.addChild(btn);
    });

    buttons[0].loadTextureNormal('toggle_on.png');
    group.forceDoLayout();
    return group;
}

