Use scheduling to decrement a counter and update the text:

```typescript
let timeLeft = 60; // seconds

const timerLabel = new ccui.Text('01:00', 'Arial', 32);
timerLabel.setTextColor(cc.color(255, 255, 255));
timerLabel.setPosition(240, 300);
this.addChild(timerLabel);

function formatTime(seconds: number): string {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return (m < 10 ? '0' : '') + m + ':' + (s < 10 ? '0' : '') + s;
}

this.schedule((dt: number) => {
    timeLeft--;
    timerLabel.setString(formatTime(timeLeft));
    if (timeLeft <= 10) {
        timerLabel.setTextColor(cc.color(255, 50, 50));
    }
    if (timeLeft <= 0) {
        this.unschedule(arguments.callee);
        this.onTimeUp();
    }
}, 1.0);
```

Toggle section visibility and resize the parent on header click:

```typescript
interface Section {
    header: ccui.Button;
    content: ccui.Layout;
    expanded: boolean;
}

const SECTION_WIDTH = 300;
const HEADER_HEIGHT = 40;
const sections: Section[] = [];
const container = new ccui.Layout();
container.setLayoutType(ccui.Layout.LINEAR_VERTICAL);
container.setSize(cc.size(SECTION_WIDTH, 500));
container.setPosition(50, 20);
this.addChild(container);

function addSection(title: string, contentHeight: number): void {
    const header = new ccui.Button('section_header.png');
    header.setScale9Enabled(true);
    header.setSize(cc.size(SECTION_WIDTH, HEADER_HEIGHT));
    header.setTitleText(title);
    header.setTitleFontSize(18);
    container.addChild(header);

    const content = new ccui.Layout();
    content.setSize(cc.size(SECTION_WIDTH, contentHeight));
    content.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    content.setBackGroundColor(cc.color(40, 40, 60));
    content.setVisible(false);
    container.addChild(content);

    const sec: Section = { header, content, expanded: false };
    sections.push(sec);

    header.addClickEventListener(() => {
        sec.expanded = !sec.expanded;
        sec.content.setVisible(sec.expanded);
        sec.content.setSize(cc.size(SECTION_WIDTH, sec.expanded ? contentHeight : 0));
        container.forceDoLayout();
    });
}

