function animatePage(idx: number): void {
    const page = pv.getPage ? pv.getItem(idx) : null;
    if (!page) return;
    const icon = page.getChildByName('icon');
    const title = page.getChildByName('title');
    if (icon) {
        icon.setOpacity(0);
        icon.setScale(0.5);
        icon.runAction(cc.spawn(
            cc.fadeIn(0.4),
            cc.scaleTo(0.4, 1.0).easing(cc.easeBackOut())
        ));
    }
    if (title) {
        title.setOpacity(0);
        title.runAction(cc.sequence(
            cc.delayTime(0.2),
            cc.fadeIn(0.3)
        ));
    }
}

pv.addEventListener((sender, type) => {
    animatePage(pv.getCurrentPageIndex());
}, this);

this.addChild(pv);
animatePage(0);
