Use ClippingNode for circular masking with a ccui widget avatar:

```typescript
function createCircularAvatar(imagePath: string, radius: number): cc.Node {
    const container = new cc.Node();

    // Create circular stencil
    const stencil = new cc.DrawNode();
    const segments = 40;
    const vertices: cc.Point[] = [];
    for (let i = 0; i < segments; i++) {
        const angle = (i / segments) * Math.PI * 2;
        vertices.push(cc.p(Math.cos(angle) * radius, Math.sin(angle) * radius));
    }
    stencil.drawPoly(vertices, cc.color(255, 255, 255, 255), 0, cc.color(0, 0, 0, 0));

    const clipper = new cc.ClippingNode(stencil);
    clipper.setAlphaThreshold(0.5);

    const avatar = new ccui.ImageView(imagePath);
    avatar.ignoreContentAdaptWithSize(false);
    avatar.setSize(cc.size(radius * 2, radius * 2));
    clipper.addChild(avatar);

    container.addChild(clipper);

    // Add border ring
    const ring = new cc.DrawNode();
    ring.drawCircle(cc.p(0, 0), radius, 0, segments, false, 2, cc.color(200, 200, 200));
    container.addChild(ring);

    return container;
}

