Add a multi-touch listener that scales the inner container:

```typescript
const sv = new ccui.ScrollView();
sv.setSize(cc.size(480, 320));
sv.setInnerContainerSize(cc.size(960, 640));
sv.setDirection(ccui.ScrollView.DIR_BOTH);
sv.setPosition(0, 0);

const mapSprite = new cc.Sprite('large_map.png');
mapSprite.setAnchorPoint(cc.p(0, 0));
sv.getInnerContainer().addChild(mapSprite);

let initialDist = 0;
let initialScale = 1;

const listener = cc.EventListener.create({
    event: cc.EventListener.TOUCH_ALL_AT_ONCE,
    onTouchesBegan: (touches) => {
        if (touches.length >= 2) {
            const p1 = touches[0].getLocation();
            const p2 = touches[1].getLocation();
            initialDist = cc.pDistance(p1, p2);
            initialScale = mapSprite.getScale();
        }
    },
    onTouchesMoved: (touches) => {
        if (touches.length >= 2) {
            const p1 = touches[0].getLocation();
            const p2 = touches[1].getLocation();
            const dist = cc.pDistance(p1, p2);
            const scale = Math.max(0.5, Math.min(3.0, initialScale * (dist / initialDist)));
            mapSprite.setScale(scale);
            const newSize = cc.size(960 * scale, 640 * scale);
            sv.setInnerContainerSize(newSize);
        }
    }
});

cc.eventManager.addListener(listener, sv);
this.addChild(sv);
```

